CustomField.formula:
IF(ISBLANK(Score_Country_of_Funds__c), "", 
    IF(Score_Country_of_Funds__c >= 4, IMAGE("/img/samples/flag_red.gif", "high") + " High",
        IF(Score_Country_of_Funds__c > 2, IMAGE("/img/samples/flag_yellow.gif", "medium") + " Medium", 
            IF(Score_Country_of_Funds__c >= 0, IMAGE("/img/samples/flag_green.gif", "low") + " Low", "")
        )
    )
)
